from azure.ai.projects import AgentClient
from datetime import datetime, timedelta

def detect_bing_staleness(agent_response):
    grounding = agent_response.get('grounding', {})
    bing_results = grounding.get('bing_search', [])

    for result in bing_results:
        pub_date = result.get('date_published')
        if pub_date:
            result_date = datetime.fromisoformat(pub_date.replace('Z', '+00:00'))
            if datetime.now() - result_date > timedelta(days=90):
                return {'stale': True, 'result': result}
    return {'stale': False}

def detect_metadata_pollution(content: str) -> dict:
    metadata_indicators = [
        'contenttype', 'content_length', 'lastmodified',
        'etag', 'blobtype', 'azure://', 'storage.azure.net'
    ]

    content_lower = content.lower()
    pollution_score = sum(1 for indicator in metadata_indicators 
                         if indicator in content_lower)

    return {
        'polluted': pollution_score > 2,
        'score': pollution_score,
        'content_sample': content[:200]
    }

import re

def scan_pii_violations(text: str) -> list:
    ssn_pattern = r'\b\d{3}-\d{2}-\d{4}\b'
    violations = []

    ssns = re.findall(ssn_pattern, text)
    if ssns:
        violations.append({
            'type': 'SSN',
            'matches': ssns,
            'policy': 'AZURE-PII-001'
        })

    return violations
